import React, { useState, useRef, useCallback, useEffect } from 'react';
import './App.css';

const API_BASE = 'http://127.0.0.1:8000';

const genres = [
  { id: 'rock', name: 'Rock' },
  { id: 'pop', name: 'Pop' },
  { id: 'jazz', name: 'Jazz' },
  { id: 'classical', name: 'Classical' },
  { id: 'hip-hop', name: 'Hip-Hop' },
  { id: 'electronic', name: 'Electronic' },
  { id: 'indie', name: 'Indie' },
  { id: 'r&b', name: 'R&B' },
  { id: 'country', name: 'Country' },
  { id: 'metal', name: 'Metal' },
  { id: 'latin', name: 'Latin' },
  { id: 'folk', name: 'Folk' },
];

const moods = [
  { id: 'happy', name: 'Happy', emoji: '☀️' },
  { id: 'energetic', name: 'Energetic', emoji: '⚡' },
  { id: 'relaxing', name: 'Relaxing', emoji: '🌊' },
  { id: 'romantic', name: 'Romantic', emoji: '💜' },
  { id: 'sad', name: 'Sad', emoji: '🌧️' },
  { id: 'focus', name: 'Focus', emoji: '🎯' },
  { id: 'party', name: 'Party', emoji: '🎉' },
  { id: 'workout', name: 'Workout', emoji: '💪' },
  { id: 'chill', name: 'Chill', emoji: '😌' },
];

function App() {
  const [selectedGenre, setSelectedGenre] = useState('');
  const [selectedMood, setSelectedMood] = useState('');
  const [selectedArtist, setSelectedArtist] = useState('');
  const [songCount, setSongCount] = useState(10);
  const [playlist, setPlaylist] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Audio player state
  const audioRef = useRef(null);
  const [currentSongId, setCurrentSongId] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Cleanup audio on unmount
  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
      }
    };
  }, []);

  const togglePlayPause = useCallback((songId, previewUrl) => {
    if (!previewUrl) return;

    if (currentSongId === songId && isPlaying) {
      // Pause current song
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      // Stop current and play new
      if (audioRef.current) {
        audioRef.current.pause();
      }
      
      const audio = new Audio(previewUrl);
      audioRef.current = audio;
      audio.play().catch(e => {
        console.error('Audio play failed:', e);
      });
      
      setCurrentSongId(songId);
      setIsPlaying(true);
      
      // Handle audio end
      audio.onended = () => {
        setIsPlaying(false);
        setCurrentSongId(null);
      };
    }
  }, [currentSongId, isPlaying]);

  const handleGenerate = async (e) => {
    e.preventDefault();
    
    if (audioRef.current) {
      audioRef.current.pause();
      setCurrentSongId(null);
      setIsPlaying(false);
    }

    setLoading(true);
    setError('');
    setPlaylist([]);

    try {
      const params = new URLSearchParams();
      if (selectedGenre) params.append('genre', selectedGenre);
      if (selectedMood) params.append('mood', selectedMood);
      if (selectedArtist) params.append('artist', selectedArtist);
      params.append('limit', songCount);

      const response = await fetch(`${API_BASE}/custom?${params}`);
      
      if (!response.ok) {
        throw new Error(`API error: ${response.status}`);
      }
      
      const data = await response.json();
      setPlaylist(data.playlist || data.songs || []);
    } catch (err) {
      setError(err.message || 'Failed to generate playlist. Is backend running on port 8000?');
    } finally {
      setLoading(false);
    }
  };

  const defaultArtwork = 'https://via.placeholder.com/120x120/1a1a1d/666666?text=Music';

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-900 via-blue-900 to-indigo-900 text-white p-8">
      <div className="max-w-4xl mx-auto">
        <header className="text-center mb-12">
          <h1 className="text-5xl md:text-6xl font-bold bg-gradient-to-r from-purple-400 via-pink-400 to-blue-400 bg-clip-text text-transparent mb-4">
            🎵 Music Playlist Generator
          </h1>
          <p className="text-xl opacity-90">Create perfect playlists based on genre, mood & artist</p>
        </header>

        <form onSubmit={handleGenerate} className="bg-white/10 backdrop-blur-lg rounded-2xl p-8 mb-12 border border-white/20">
          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Genre */}
            <div>
              <label className="block text-sm font-medium mb-2">Genre</label>
              <select 
                value={selectedGenre} 
                onChange={(e) => setSelectedGenre(e.target.value)}
                className="w-full p-3 bg-white/20 border border-white/30 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-400 text-white placeholder-white/70"
              >
                <option value="">Any Genre</option>
                {genres.map(genre => (
                  <option key={genre.id} value={genre.id}>{genre.name}</option>
                ))}
              </select>
            </div>

            {/* Mood */}
            <div>
              <label className="block text-sm font-medium mb-2">Mood</label>
              <select 
                value={selectedMood} 
                onChange={(e) => setSelectedMood(e.target.value)}
                className="w-full p-3 bg-white/20 border border-white/30 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-400 text-white placeholder-white/70"
              >
                <option value="">Any Mood</option>
                {moods.map(mood => (
                  <option key={mood.id} value={mood.id}>{mood.emoji} {mood.name}</option>
                ))}
              </select>
            </div>

            {/* Artist */}
            <div>
              <label className="block text-sm font-medium mb-2">Artist (optional)</label>
              <input 
                type="text" 
                value={selectedArtist}
                onChange={(e) => setSelectedArtist(e.target.value)}
                placeholder="Taylor Swift, The Weeknd..."
                className="w-full p-3 bg-white/20 border border-white/30 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-400 text-white placeholder-white/70"
              />
            </div>

            {/* Song Count */}
            <div className="flex items-end">
              <div>
                <label className="block text-sm font-medium mb-2">Number of Songs</label>
                <input 
                  type="range" 
                  min="5" max="50" step="5"
                  value={songCount}
                  onChange={(e) => setSongCount(Number(e.target.value))}
                  className="w-full h-2 bg-white/30 rounded-lg appearance-none cursor-pointer accent-purple-400"
                />
                <div className="text-sm opacity-75 mt-1">{songCount} songs</div>
              </div>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full mt-8 bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 px-8 rounded-2xl text-lg shadow-2xl hover:shadow-purple-500/25 transition-all duration-300 transform hover:-translate-y-1"
          >
            {loading ? '🎧 Generating Playlist...' : '✨ Generate My Playlist'}
          </button>

          {error && (
            <div className="mt-4 p-4 bg-red-500/20 border border-red-500/50 rounded-xl text-red-100">
              {error}
            </div>
          )}
        </form>

        {playlist.length > 0 && (
          <div>
            <h2 className="text-3xl font-bold mb-8 text-center bg-gradient-to-r from-green-400 to-teal-400 bg-clip-text text-transparent">
              Your Perfect Playlist 🎶
            </h2>
            <div className="playlist-grid">
              {playlist.map((song, index) => (
                <div key={`${song.id}-${index}`} className="group bg-white/10 backdrop-blur-lg rounded-2xl p-6 border border-white/20 hover:bg-white/20 transition-all duration-300 hover:scale-105 hover:shadow-2xl">
                  <div className="relative">
                    <img 
                      src={song.artwork || song.album?.images?.[0]?.url || defaultArtwork} 
                      alt={song.name || song.title}
                      className="w-full h-48 object-cover rounded-xl shadow-lg mb-4"
                    />
                    {song.preview_url && (
                      <button
                        onClick={() => togglePlayPause(song.id || index, song.preview_url)}
                        className={`absolute bottom-3 right-3 w-12 h-12 rounded-full flex items-center justify-center text-xl shadow-lg transition-all duration-200 ${
                          currentSongId === (song.id || index) && isPlaying 
                            ? 'bg-red-500 text-white scale-110 shadow-red-500/50' 
                            : 'bg-white/90 hover:bg-white shadow-white/50 group-hover:scale-110'
                        }`}
                        title={currentSongId === (song.id || index) && isPlaying ? 'Pause' : 'Play Preview'}
                      >
                        {currentSongId === (song.id || index) && isPlaying ? '⏸️' : '▶️'}
                      </button>
                    )}
                  </div>
                  
                  <h3 className="font-bold text-lg mb-1 line-clamp-1">{song.name || song.title}</h3>
                  <p className="text-gray-300 mb-2 opacity-90">{song.artists?.[0]?.name || song.artist}</p>
                  <p className="text-sm text-gray-400">{song.album?.name || 'Album'}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
